import socket
import network
import time
import json
import ubinascii
import uhashlib
import ustruct

# WiFi credentials
WIFI_SSID = "your_wifi_ssid"
WIFI_PASSWORD = "your_wifi_password"

# Create and connect to WiFi
wlan = network.WLAN(network.STA_IF)
wlan.active(True)
wlan.connect(WIFI_SSID, WIFI_PASSWORD)

while not wlan.isconnected():
    time.sleep(1)

print("Connected to WiFi")
print("IP address:", wlan.ifconfig()[0])

# Create socket
server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
server_socket.bind((wlan.ifconfig()[0], 80))
server_socket.listen(5)

def generate_websocket_key(key):
    GUID = "258EAFA5-E914-47DA-95CA-C5AB0DC85B11"
    key = key + GUID
    sha1 = uhashlib.sha1(key.encode())
    return ubinascii.b2a_base64(sha1.digest())[:-1].decode()

def handle_websocket_connection(client_socket):
    try:
        # Read HTTP headers
        request = client_socket.recv(1024).decode()
        if "Upgrade: websocket" in request:
            # Extract WebSocket key
            key_line = [line for line in request.split('\n') if 'Sec-WebSocket-Key:' in line]
            if key_line:
                key = key_line[0].split(':')[1].strip()
                response_key = generate_websocket_key(key)
                
                # Send WebSocket handshake response
                response = (
                    "HTTP/1.1 101 Switching Protocols\r\n"
                    "Upgrade: websocket\r\n"
                    "Connection: Upgrade\r\n"
                    "Sec-WebSocket-Accept: " + response_key + "\r\n\r\n"
                )
                client_socket.send(response.encode())
                
                # Handle WebSocket messages
                while True:
                    try:
                        # Receive WebSocket frame
                        header = client_socket.recv(2)
                        if not header:
                            break
                            
                        # Parse frame
                        fin = header[0] & 0x80
                        opcode = header[0] & 0x0F
                        mask = header[1] & 0x80
                        payload_len = header[1] & 0x7F
                        
                        if payload_len == 126:
                            payload_len = ustruct.unpack('>H', client_socket.recv(2))[0]
                        elif payload_len == 127:
                            payload_len = ustruct.unpack('>Q', client_socket.recv(8))[0]
                            
                        if mask:
                            mask_key = client_socket.recv(4)
                            
                        payload = client_socket.recv(payload_len)
                        
                        if mask:
                            # Unmask payload
                            payload = bytearray(payload)
                            for i in range(len(payload)):
                                payload[i] ^= mask_key[i % 4]
                            payload = bytes(payload)
                        
                        # Handle JSON command
                        if opcode == 1:  # Text frame
                            try:
                                command = json.loads(payload.decode())
                                print("Received command:", command)
                                
                                # Process command
                                if command.get("action") == "turn_on":
                                    # Your turn on logic here
                                    print("Turning on device")
                                    response = {"status": "turned_on"}
                                elif command.get("action") == "turn_off":
                                    # Your turn off logic here
                                    print("Turning off device")
                                    response = {"status": "turned_off"}
                                else:
                                    response = {"status": "unknown_command"}
                                
                                # Send response back
                                response_json = json.dumps(response)
                                client_socket.send(
                                    b'\x81' + len(response_json).to_bytes(1, 'big') + response_json.encode()
                                )
                                
                            except Exception as e:
                                print("Error processing command:", e)
                                error_response = {"error": "Invalid JSON"}
                                client_socket.send(
                                    b'\x81' + len(json.dumps(error_response)).to_bytes(1, 'big') + json.dumps(error_response).encode()
                                )
                                
                    except Exception as e:
                        print("WebSocket error:", e)
                        break
                        
    except Exception as e:
        print("Connection error:", e)
    finally:
        client_socket.close()

print("WebSocket server started on http://" + wlan.ifconfig()[0] + ":80")

while True:
    try:
        client_socket, addr = server_socket.accept()
        print("Client connected from", addr)
        handle_websocket_connection(client_socket)
    except Exception as e:
        print("Server error:", e)
        time.sleep(1)